// is Prettier's job (see `npx prettier --check`), not ESLint's.
//
// `transpiled/` is jco's generated JS output (regenerated by `task build`,
// gitignored) and must never be linted as hand-written source.
export default [
  {
    ignores: ["node_modules/**", "transpiled/**"],
  },
  js.configs.recommended,
  {
    languageOptions: {
      ecmaVersion: "latest",
      sourceType: "module",
      // Node globals used by the native fixture adapter and its tests
      // (this component is exercised server-side via `node --test`).
      globals: {
        Buffer: "readonly",
        TextDecoder: "readonly",
      },
    },
  },
];
